import { unstable_cache } from "next/cache";

export interface Post {
  id: string;
  title: string;
  content: string;
  createdAt: string;
}

// In-memory store seeded with one example post
const store: Post[] = [
  {
    id: "1",
    title: "First Post",
    content: "Welcome to the posts app!",
    createdAt: new Date(Date.now() - 86400000).toISOString(),
  },
];

/**
 * Add a new post to the store.
 */
export function addPost(post: Post): void {
  store.unshift(post); // newest first
}

/**
 * Return all posts.
 * Called directly by the cached wrapper – not exported directly to
 * prevent callers from accidentally bypassing the cache layer.
 */
function readPosts(): Post[] {
  // Return a copy so external code can't mutate the store
  return [...store];
}

/**
 * Cached post-list reader.
 *
 * Uses the "posts" cache tag so that `revalidateTag("posts")` inside
 * the Server Action guarantees the **next** page load re-fetches data
 * and never serves stale content.
 */
export const getPosts = unstable_cache(
  readPosts,
  ["posts-list-key"],
  { tags: ["posts"] },
);

"use server";

import { revalidateTag } from "next/cache";
import { addPost } from "@/lib/posts";

export interface CreatePostResult {
  success: boolean;
  error?: string;
}

/**
 * Server Action – creates a new post and invalidates the "posts"
 * cache tag so the next page load fetches fresh data.
 *
 * Calling `revalidateTag("posts")` marks every cached entry tagged
 * with "posts" as stale.  When the page re-renders (automatically
 * after a Server‑Action form submission), any data read with the
 * "posts" tag will re-execute and return the latest results –
 * stale content is never served.
 */
export async function createPost(
  formData: FormData,
): Promise<CreatePostResult> {
  const title = formData.get("title")?.toString().trim();
  const content = formData.get("content")?.toString().trim();

  // --- Validation ---
  if (!title) {
    return { success: false, error: "Title is required." };
  }
  if (!content) {
    return { success: false, error: "Content is required." };
  }

  // --- Persist ---
  addPost({
    id: String(Date.now()),
    title,
    content,
    createdAt: new Date().toISOString(),
  });

  // --- Cache invalidation ---
  // This is the key step: marking the "posts" tag as stale guarantees
  // the NEXT page render re-fetches data instead of serving a cached copy.
  revalidateTag("posts");

  return { success: true };
}

