"use server";

import { revalidateTag } from "next/cache";
import { addPost } from "@/lib/posts";

export interface CreatePostResult {
  success: boolean;
  error?: string;
}

/**
 * Server Action – creates a new post and invalidates the "posts"
 * cache tag so the next page load fetches fresh data.
 *
 * The `{ expire: 0 }` profile tells Next.js to **immediately** expire
 * every cache entry tagged with "posts".  This guarantees the next
 * render re-fetches the list from scratch instead of serving stale
 * stale-while-revalidate content.
 */
export async function createPost(
  formData: FormData,
): Promise<CreatePostResult> {
  const title = formData.get("title")?.toString().trim();
  const content = formData.get("content")?.toString().trim();

  // --- Validation ---
  if (!title) {
    return { success: false, error: "Title is required." };
  }
  if (!content) {
    return { success: false, error: "Content is required." };
  }

  // --- Persist ---
  addPost({
    id: String(Date.now()),
    title,
    content,
    createdAt: new Date().toISOString(),
  });

  // --- Cache invalidation ---
  // `{ expire: 0 }` forces immediate expiry so no stale-while-revalidate
  // shortcut is taken – the very next data read with the "posts" tag runs
  // the underlying function again and returns the latest results.
  revalidateTag("posts", { expire: 0 });

  return { success: true };
}

